    {'label': 'Cambrian Explosion', 'years_ago': 541_000_000, 'event': 'The Cambrian Explosion: most major animal body plans appear within ~20 million years — an evolutionary radiation driven by predation, oxygen, and ecological opportunity.', 'category': 'evolution', 'icon': '🦐'},
