    {'label': 'First Dinosaurs', 'years_ago': 230_000_000, 'event': 'Dinosaurs evolve and come to dominate the Earth for 165 million years — the longest reign of any land animal group.', 'category': 'evolution', 'icon': '🦕'},
    {'label': 'Dinosaur Extinction', 'years_ago': 66_000_000, 'event': 'A 10km asteroid strikes Mexico (Chicxulub). 75% of species go extinct. Small feathered dinosaurs — birds — survive. Mammals diversify.', 'category': 'evolution', 'icon': '☄️'},
